            end
        end
    end
    return -1
end
function x930127_CheckAndAddjy(varMap, varPlayer)
    --查询当前buffid
    local curIndex = 0
    for varI, item in x930127_var_ExcObjID do
        local haveImpact  = IsHaveSpecificImpact(varMap, varPlayer, item.buffID)
        if haveImpact > 0 then
            curIndex = varI
        end
    end


    if curIndex >= 1 then
        --判断培养的经验值
        local jinyan = GetPlayerGameData(varMap, varPlayer, MD_JIERIQINGDIAN_DATE[1], MD_JIERIQINGDIAN_DATE[2], MD_JIERIQINGDIAN_DATE[3])

        if jinyan < x930127_var_pyexp*curIndex then
            --经验不够，需要培养

            --再判断当前出战的坐骑是不是
            if 1 == IsHaveMount(varMap, varPlayer, -1) then
                -- 玩家当前正在骑乘坐骑
                local mountId = GetHorseDataID(varMap, varPlayer, 0)
                local tujianid = x930127_var_ExcObjID[curIndex].targetID
                local mounttype = x930127_GetHorseType(varMap,varPlayer, mountId)
                local tujiantype = x930127_GetHorseType(varMap,varPlayer, tujianid)

                if mounttype ~= -1 and mounttype == tujiantype then
                    local after = jinyan+x930127_var_pyexppermin
                    local add = x930127_var_pyexppermin
                    SetPlayerGameData(varMap, varPlayer, MD_JIERIQINGDIAN_DATE[1], MD_JIERIQINGDIAN_DATE[2], MD_JIERIQINGDIAN_DATE[3], after)
                    Msg2Player(varMap, varPlayer,format("坐骑图鉴出战中，增加了%d经验，当前总经验%d", add, after),8,3)
                    Msg2Player(varMap, varPlayer,format("坐骑图鉴出战中，增加了%d经验，当前总经验%d", add, after),8,2)
                end

            end



            return
        end
    end

end

