    --if x930127_var_ExcObjID[nextIndex].useyuan == 1 then
    --    --可以使用生命源龙
    --    if IsHaveHorse( varMap, varPlayer, x930127_var_ExcObjID[nextIndex].targetID) == 0 and IsHaveHorse( varMap, varPlayer, curYl.id) == 0 then
