    --end





    if curIndex > 0 then
        local varRet = CancelSpecificImpact( varMap, varPlayer, x930127_var_ExcObjID[curIndex].buffID)
        if varRet <= 0 then
            Msg2Player(varMap, varPlayer,"删除效果"..x930127_var_ExcObjID[curIndex].buffID.."失败",8,3)
