    Msg2Player(varMap, varPlayer,"添加效果"..x930127_var_ExcObjID[nextIndex].buffID.."成功",8,3)
    Msg2Player(varMap, varPlayer,"添加效果"..x930127_var_ExcObjID[nextIndex].buffID.."成功",8,2)

    --清除当前经验
